W ok (L2 "Barra de tareas alineada a la izquierda." "Taskbar aligned to the left.")
'@
       Undo=@'
reg add "HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\Advanced" /v TaskbarAl /t REG_DWORD /d 1 /f | Out-Null
