W ok (L2 "IA del Bloc de notas desactivada." "Notepad AI disabled.")
'@
       Undo=@'
reg delete "HKLM\SOFTWARE\Policies\WindowsNotepad" /v DisableAIFeatures /f 2>$null | Out-Null
