    }
}
function T([string]$k) {
    $tbl = $script:Strings[$script:Lang]
    if ($tbl -and $tbl.ContainsKey($k)) { return [string]$tbl[$k] }
    $es = $script:Strings['es']
    if ($es -and $es.ContainsKey($k)) { return [string]$es[$k] }
    return $k
}

