# Restaurar tamano/posicion de ventana guardados
try {
    # Bug real (VT2-8, 2a parte): en pantallas menores que el minimo de diseno
    # (p.ej. 1024x768), el MinWidth=1180 del XAML impedia encoger la ventana aunque
    # el clamp bajara Width -> desbordaba igual y los controles del borde derecho
    # quedaban inalcanzables. El MINIMO de diseno (y el tamano por defecto del XAML,
    # 1480x880, para el primer arranque sin geometria guardada) se recortan SIEMPRE
    # a la pantalla virtual real.
    $vwS = [System.Windows.SystemParameters]::VirtualScreenWidth
    $vhS = [System.Windows.SystemParameters]::VirtualScreenHeight
    if ($window.MinWidth  -gt $vwS) { $window.MinWidth  = $vwS }
    if ($window.MinHeight -gt $vhS) { $window.MinHeight = $vhS }
    if ($window.Width  -gt $vwS) { $window.Width  = $vwS }
    if ($window.Height -gt $vhS) { $window.Height = $vhS }
    if ($script:WinGeom -and $script:WinGeom.W -gt 400) {
        # Bug real (VT2-8, cazado en la VM del fuego): una geometria guardada MAYOR que
        # la pantalla actual (settings heredados de un monitor grande) dejaba la ventana
        # DESBORDADA y los controles del borde derecho INALCANZABLES (los "Ejecutar" de
        # Reparacion quedaban fuera de una pantalla de 1024x768 con W=1480 guardado).
        # El TAMANO tambien se recorta a la pantalla virtual, no solo la posicion.
        $vx = [System.Windows.SystemParameters]::VirtualScreenLeft
        $vy = [System.Windows.SystemParameters]::VirtualScreenTop
        $vw = [System.Windows.SystemParameters]::VirtualScreenWidth
        $vh = [System.Windows.SystemParameters]::VirtualScreenHeight
        $gw = [double]$script:WinGeom.W; if ($gw -gt $vw) { $gw = $vw }
        $gh = [double]$script:WinGeom.H; if ($gh -gt $vh) { $gh = $vh }
        $window.Width  = $gw
        $window.Height = $gh
        if ($null -ne $script:WinGeom.T -and $null -ne $script:WinGeom.L) {
            # F1-B2 (VT2): sin exigir T,L>=0 — en multi-monitor el monitor a la izquierda
            # del primario da Left NEGATIVO legitimo; el clamp de abajo ya recorta a la
            # pantalla virtual real (que tambien tiene origen negativo en ese caso).
            # Guard anti fuera-de-pantalla: la ventana queda ENTERA dentro de la pantalla
            # virtual (antes solo se recortaba la esquina superior izquierda).
            $top  = [double]$script:WinGeom.T
            $left = [double]$script:WinGeom.L
            $maxL = $vx + $vw - $gw
            $maxT = $vy + $vh - $gh
            if ($left -lt $vx) { $left = $vx }; if ($left -gt $maxL) { $left = $maxL }
            if ($top  -lt $vy) { $top  = $vy }; if ($top  -gt $maxT) { $top  = $maxT }
            $window.WindowStartupLocation = 'Manual'
            $window.Top  = $top
            $window.Left = $left
        }
    }
} catch {}

$window.Add_Closing({
    param($s, $e)
    if ($script:State.Running) {
        $r = Show-WpiMessage(
            'Hay un proceso en marcha. Si cierras ahora, las instalaciones en curso seguiran en segundo plano sin supervision. Cerrar igualmente?',
            'Winzard', 'YesNo', 'Warning')
        if ($r -ne 'Yes') { $e.Cancel = $true; return }
        $script:State.Cancel = $true
    }
    if (-not $script:Skip_Closing_Save) { Save-Settings }
    $script:Timer.Stop()
    # Liberar el mutex de instancia unica (el SO lo reclama igual, pero es lo correcto).
    try { $script:SingleInstance.ReleaseMutex() } catch {}
})

# UX-5 (VT2-8, encargo del usuario): la deteccion automatica de apps instaladas
# corria SINCRONA en ContentRendered -> 15-25 s de cursor ocupado con la ventana
# YA visible (la app parecia lenta o colgada nada mas abrir). Ahora corre BAJO la
# splash, con su propia etapa visible (ver justo antes del revelado), y la ventana
# se muestra SOLO cuando todo esta cargado: lista para usar del tiron.

# C2: si el idioma es ingles, traduce toda la interfaz ya construida (chrome,
# barra inferior, panel inicial). Los paneles perezosos se traducen al abrirse.
Update-WpiSplash 'Aplicando tu tema y tus ajustes...' 'Applying your theme and settings...'
try { Translate-Tree $window; Apply-WpiToolTips $window } catch {}
# Tras traducir: fija el contador "(0)" del boton de aplicar tweaks (usa Tr, no filtra)
try { Update-TweakCount } catch {}

if ($SelfTestGui) {
    $missing = New-Object System.Collections.Generic.List[string]
    foreach ($name in @(
        'SideList','AppsScroll','Lists','TweaksScroll','TweaksList','UpgradesScroll','UpgradesList',
        'DebloatScroll','DebloatList','DriversScroll','DriversList','WinUpdateScroll','WinUpdateList',
        'RepairScroll','RepairList','GamingScroll','GamingList','RecoveryScroll','RecoveryList','CreateIsoScroll','CreateIsoList','SummaryScroll','SummaryList',
        'QuickStartScroll','QuickStartList','LogList','Prog','StatusText','BtnInstall','BtnCancel','CboLang','CboTheme'
    )) {
        try { if (-not $window.FindName($name)) { $missing.Add($name) } } catch { $missing.Add($name) }
    }

    if ($missing.Count -gt 0) {
        Write-Host ('[FAIL] SelfTestGui: faltan controles: {0}' -f ($missing -join ', ')) -ForegroundColor Red
        exit 1
    }

    try { Build-RepairUI; Translate-Tree $script:RepairScroll; Apply-WpiToolTips $script:RepairScroll } catch { Write-Host ('[FAIL] SelfTestGui: Repair UI: {0}' -f $_.Exception.Message) -ForegroundColor Red; exit 1 }
    try { Build-CreateIsoUI; Translate-Tree $script:CreateIsoScroll; Apply-WpiToolTips $script:CreateIsoScroll } catch { Write-Host ('[FAIL] SelfTestGui: Create ISO UI: {0}' -f $_.Exception.Message) -ForegroundColor Red; exit 1 }
    try { Build-RecoveryUI; Translate-Tree $script:RecoveryScroll; Apply-WpiToolTips $script:RecoveryScroll } catch { Write-Host ('[FAIL] SelfTestGui: Recovery UI: {0}' -f $_.Exception.Message) -ForegroundColor Red; exit 1 }
    try { Build-GamingUI; Translate-Tree $script:GamingScroll; Apply-WpiToolTips $script:GamingScroll } catch { Write-Host ('[FAIL] SelfTestGui: Gaming UI: {0}' -f $_.Exception.Message) -ForegroundColor Red; exit 1 }

    Write-Host '[OK] SelfTestGui: ventana WPF, controles criticos y paneles Reparacion/Crear ISO construidos correctamente.' -ForegroundColor Green
    exit 0
}

if ($BuildIsoKit) {
    if (-not $IsoPath -or -not (Test-Path -LiteralPath $IsoPath -PathType Leaf)) {
        Write-Host ('[FAIL] BuildIsoKit: no existe la ISO origen: {0}' -f $IsoPath) -ForegroundColor Red
        exit 1
    }
    if (-not $IsoOutDir) { $IsoOutDir = Get-WpiDir 'ISO' }
    try { if (-not (Test-Path -LiteralPath $IsoOutDir -PathType Container)) { New-Item -ItemType Directory -Path $IsoOutDir -Force | Out-Null } } catch {
        Write-Host ('[FAIL] BuildIsoKit: no se pudo crear la carpeta de salida: {0}' -f $_.Exception.Message) -ForegroundColor Red
        exit 1
    }

    Init-IsoWizard
    $script:Wiz.SrcIso = (Resolve-Path -LiteralPath $IsoPath).Path
    $script:Wiz.OutDir = (Resolve-Path -LiteralPath $IsoOutDir).Path
    $script:Wiz.IsoName = $IsoName
    $script:Wiz.WorkDir = Join-Path $script:Wiz.OutDir '_work'
    $script:Wiz.AppIds = @()
    $script:Wiz.AllEditions = $false
    $script:Wiz.Locale = 'es-ES'
    $script:Wiz.AccountName = 'Usuario'
    $script:Wiz.AccountPassword = ''
    # F6-B1 (VT2): el kit headless heredaba de Init-IsoWizard ~56 tweaks marcados y TODO
    # el catalogo de debloat, sin que quien automatiza lo pidiera (sorpresa peligrosa).
    # Ahora sale NEUTRO por defecto; el contenido se pide con -IsoTweaksAll/-IsoDebloatAll
    # o editando kit-config.json/preset_tweaks.txt. La GUI no cambia: alli el usuario VE
    # las casillas pre-marcadas y las edita en pantalla.
    if (-not $IsoTweaksAll)  { $script:Wiz.TweakNames  = @() }
    if (-not $IsoDebloatAll) { $script:Wiz.DebloatPkgs = @() }
    Write-Host ('[i] BuildIsoKit: tweaks={0} debloat={1} apps={2}  (contenido opt-in: -IsoTweaksAll / -IsoDebloatAll o editar kit-config.json)' -f @($script:Wiz.TweakNames).Count, @($script:Wiz.DebloatPkgs).Count, @($script:Wiz.AppIds).Count) -ForegroundColor Gray

    $kit = New-IsoBuildKit
    if ($kit -and (Test-Path -LiteralPath (Join-Path $kit 'kit-config.json') -PathType Leaf)) {
        Write-Host ('[OK] BuildIsoKit: kit generado en {0}' -f $kit) -ForegroundColor Green
        exit 0
    }
    Write-Host '[FAIL] BuildIsoKit: no se genero el kit.' -ForegroundColor Red
    exit 1
}

# P4: aviso suave (no bloqueante) si los ajustes estaban corruptos y se restauraron.
if ($script:SettingsRestored) {
    try { $script:StatusText.Text = (Tr 'Los ajustes estaban danados y se han restaurado a los valores por defecto (copia en wpi_settings.json.corrupt.bak).') } catch {}
}

# UX-5 (VT2-8): la deteccion de apps instaladas (la fase LARGA del arranque,
# 15-25 s con muchos programas) corre AQUI, bajo la splash y con etapa visible,
# en vez de congelar la ventana ya mostrada (antes iba en ContentRendered).
if ($Config.AutoDetectInstalled) {
    Update-WpiSplash 'Detectando tus programas instalados...' 'Detecting your installed programs...'
    try { Invoke-DetectHighlight $false | Out-Null } catch {}
}

# UX-1 (VT2): warm-up del motor async DURANTE la splash. El primer runspace de un
# proceso paga el coste de arranque (ensamblados/JIT) y por eso la primera tarjeta
# aplicada tras abrir la GUI tenia latencia (hallazgo "cold-start" de la 1a pasada).
# Se paga aqui ese coste, con la splash aun visible, y el primer Start-Worker real
# sale ya caliente. Mismo perfil que Start-Worker (MTA) y desechable.
Update-WpiSplash 'Preparando el motor de instalaciones...' 'Warming up the install engine...'
try {
    $__wuRS = [runspacefactory]::CreateRunspace()
    $__wuRS.ApartmentState = 'MTA'
    $__wuRS.Open()
    $__wuPS = [powershell]::Create()
    $__wuPS.Runspace = $__wuRS
    [void]$__wuPS.AddScript('param($x) $x').AddArgument(1)
    [void]$__wuPS.Invoke()
    $__wuPS.Dispose(); $__wuRS.Close(); $__wuRS.Dispose()
} catch {}

# La ventana principal ya esta lista: la splash se retira SIEMPRE justo antes
# de mostrarla (Close-WpiSplash es inofensiva si nunca llego a crearse).
Update-WpiSplash 'Todo listo. Abriendo Winzard...' 'All set. Opening Winzard...'
try { Close-WpiSplash } catch {}
[void]$window.ShowDialog()
Write-Host ''
Write-Host ('[OK] Winzard v{0} cerrado. Logs forenses en: {1}' -f $WpiVersion, $Config.LogDir) -ForegroundColor Green
